  "importance": 4,
  "summary": "schemas/xananode-relationship-types.schema.v0.5.0.json is preserved as a raw protocol artifact in the XanaNode canonical substrate.",
  "artifact_path": "schemas/xananode-relationship-types.schema.v0.5.0.json",
